let ReportPeriod = {W_ReportPeriod};
let EndTime = now();
let CurrentStart = EndTime - ReportPeriod;
let ReportDays = ReportPeriod / 1d;
let MinUserActivity = {W_MinUserActivity};
let ServiceAccountUPNs = toscalar(union isfuzzy=true (datatable(UPN:string)[]), (_GetWatchlist('service-accounts') | project UPN = tostring(UPN)) | summarize make_set(tolower(UPN)));
let ExcludedUPNs = dynamic(['app@sharepoint','system@sharepoint']);
let MeaningfulOps = dynamic(['Send','SendAs','SendOnBehalf','FileUploaded','FileModified','FileCheckedIn','FileRenamed','FileMoved','FileDownloaded','ClientViewSignaled','PageViewed','MessageSent','MessageEdited','ChatCreated','TeamCreated','ChannelAdded','MeetingParticipantDetail']);
let PerUser = OfficeActivity
| where TimeGenerated >= CurrentStart and TimeGenerated < EndTime
| where UserType == 'Regular'
| where Operation in (MeaningfulOps)
| extend UPN = tolower(tostring(UserId))
| where UPN !contains '#ext#'
| where UPN !in (ExcludedUPNs) and UPN !in (ServiceAccountUPNs)
| summarize Events = count() by UPN, Workload = tostring(OfficeWorkload)
| where Events >= MinUserActivity
| extend GroupKey = 'All', EventsPerDay = round(todouble(Events) / ReportDays, 2);
let Medians = PerUser | summarize Median = percentile(EventsPerDay, 50) by GroupKey, Workload;
let MAD = PerUser | join kind=inner Medians on GroupKey, Workload | extend AbsDev = abs(EventsPerDay - Median) | summarize MAD = percentile(AbsDev, 50) by GroupKey, Workload;
PerUser
| summarize Users = dcount(UPN), Median = round(percentile(EventsPerDay, 50), 2), P25 = round(percentile(EventsPerDay, 25), 2), P75 = round(percentile(EventsPerDay, 75), 2), P90 = round(percentile(EventsPerDay, 90), 2) by GroupKey, Workload
| join kind=inner MAD on GroupKey, Workload
| project Workload, Users, Median, P25, P75, P90, MAD = round(MAD, 2)
| order by Workload asc

let ReportPeriod = {W_ReportPeriod};
let EndTime = now();
let CurrentStart = EndTime - ReportPeriod;
let ReportDays = ReportPeriod / 1d;
let MinUserActivity = {W_MinUserActivity};
let OutlierZ = {W_OutlierZ};
let ServiceAccountUPNs = toscalar(union isfuzzy=true (datatable(UPN:string)[]), (_GetWatchlist('service-accounts') | project UPN = tostring(UPN)) | summarize make_set(tolower(UPN)));
let ExcludedUPNs = dynamic(['app@sharepoint','system@sharepoint']);
let MeaningfulOps = dynamic(['Send','SendAs','SendOnBehalf','FileUploaded','FileModified','FileCheckedIn','FileRenamed','FileMoved','FileDownloaded','ClientViewSignaled','PageViewed','MessageSent','MessageEdited','ChatCreated','TeamCreated','ChannelAdded','MeetingParticipantDetail']);
let PerUser = OfficeActivity
| where TimeGenerated >= CurrentStart and TimeGenerated < EndTime
| where UserType == 'Regular'
| where Operation in (MeaningfulOps)
| extend UPN = tolower(tostring(UserId))
| where UPN !contains '#ext#'
| where UPN !in (ExcludedUPNs) and UPN !in (ServiceAccountUPNs)
| summarize Events = count() by UPN, Workload = tostring(OfficeWorkload)
| where Events >= MinUserActivity
| extend GroupKey = 'All', EventsPerDay = round(todouble(Events) / ReportDays, 2);
let Stats = PerUser | summarize Median = percentile(EventsPerDay, 50), P25 = percentile(EventsPerDay, 25), P75 = percentile(EventsPerDay, 75), P90 = percentile(EventsPerDay, 90) by GroupKey, Workload;
let MAD = PerUser | join kind=inner Stats on GroupKey, Workload | extend AbsDev = abs(EventsPerDay - Median) | summarize MAD = percentile(AbsDev, 50) by GroupKey, Workload;
let UserList = SigninLogs | where TimeGenerated >= CurrentStart | where UserType =~ 'Member' | summarize arg_max(TimeGenerated, UserDisplayName) by UPN = tolower(UserPrincipalName) | project UPN, UserDisplayName;
PerUser
| join kind=inner Stats on GroupKey, Workload
| join kind=inner MAD on GroupKey, Workload
| extend ModifiedZ = iff(MAD == 0, 0.0, round(0.6745 * (EventsPerDay - Median) / MAD, 2))
| extend PercentileBand = case(EventsPerDay < P25, 'Below P25 (low vs peers)', EventsPerDay < Median, 'P25-P50', EventsPerDay < P75, 'P50-P75', EventsPerDay < P90, 'P75-P90', 'Above P90 (high vs peers)')
| extend OrgFlag = iff(abs(ModifiedZ) > OutlierZ, 'Outlier - review only', 'Typical')
| join kind=leftouter UserList on UPN
| where isnotempty(UserDisplayName)
| project UserDisplayName, UPN, Workload, UserEventsPerDay = EventsPerDay, GroupMedian = round(Median, 2), PercentileBand, ModifiedZ, OrgFlag
| order by Workload asc, ModifiedZ desc
